  "name": "My Code Mod",                   // Modリストに表示されるMod名
  "description": "新しいアクションとMod設定",  // Modリストに表示されるModの説明
  "sources": ["src/*.cs"],                 // ソースファイルを収集するグロブパターン（すべての ".cs" ファイルを含む）
  "author": "programmer",                  // 作者
  "depends": ["core"]                      // コアゲームへの依存（手動でMod読み込み順序を設定する必要なし）
